// Abix PWA — Service Worker v2
// Intercepts /manifest.json and /icon*.png so Cloudflare Workers
// routing cannot block them after first SW activation.
const CACHE = 'abix-v2';

const MANIFEST_JSON = {"name": "Abix \u2013 Money Tracker", "short_name": "Abix", "description": "Personal expense and balance tracker. All data stays on your device.", "start_url": "/", "scope": "/", "display": "standalone", "background_color": "#0f1117", "theme_color": "#1a1f2e", "orientation": "portrait", "prefer_related_applications": false, "icons": [{"src": "/icon-192.png", "sizes": "192x192", "type": "image/png", "purpose": "any"}, {"src": "/icon-512.png", "sizes": "512x512", "type": "image/png", "purpose": "any maskable"}], "categories": ["finance", "productivity"]};

const ICON_B64 = '';

function b64ToUint8(b64) {
  const bin = atob(b64);
  const buf = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
  return buf;
}

self.addEventListener('install', function(e) {
  e.waitUntil(
    caches.open(CACHE).then(function(cache) {
      // Pre-seed manifest.json in cache so Chrome can read it
      cache.put(
        new Request('/manifest.json'),
        new Response(JSON.stringify(MANIFEST_JSON), {
          headers: { 'Content-Type': 'application/manifest+json' }
        })
      );
      // Pre-seed icons (same PNG base64, resized by browser)
      const iconBytes = b64ToUint8(ICON_B64);
      const iconBlob192 = new Blob([iconBytes], { type: 'image/png' });
      const iconBlob512 = new Blob([iconBytes], { type: 'image/png' });
      cache.put(new Request('/icon-192.png'), new Response(iconBlob192, { headers: { 'Content-Type': 'image/png' } }));
      cache.put(new Request('/icon-512.png'), new Response(iconBlob512, { headers: { 'Content-Type': 'image/png' } }));
      return Promise.resolve();
    }).then(function() {
      return self.skipWaiting();
    })
  );
});

self.addEventListener('activate', function(e) {
  e.waitUntil(
    caches.keys().then(function(keys) {
      return Promise.all(
        keys.filter(function(k) { return k !== CACHE; }).map(function(k) { return caches.delete(k); })
      );
    }).then(function() { return clients.claim(); })
  );
});

self.addEventListener('fetch', function(e) {
  if (e.request.method !== 'GET') return;
  e.respondWith(
    caches.open(CACHE).then(function(cache) {
      return cache.match(e.request).then(function(cached) {
        var fresh = fetch(e.request).then(function(resp) {
          if (resp && resp.status === 200) cache.put(e.request, resp.clone());
          return resp;
        }).catch(function() { return cached; });
        return cached || fresh;
      });
    })
  );
});
